INSERT INTO public.program_events (id, session_id, program_id, day_id, speaker_id, title, start_time, end_time, event_type, location, track, parallel_group, status, description, sort_order, meta, created_at, updated_at) VALUES ('event-6c4f2b53', 'session-e6636776', 'program-e6636776', 'day-program-e6636776-1', NULL, 'Сессия-знакомство', '15:00', '16:00', 'Групповая работа', '', 'Общий поток', 'A', 'planned', '24 апреля с 15:00 до 16:00 запланирован вводный и командообразующий блок: сначала участники пройдут приветствие, энерджайзер и ознакомятся с правилами работы, затем состоится вступительное слово-инструктаж от о. Алипия, после чего с 15:20 до 15:50 пройдет знакомство в интерактивном формате с карточками и тремя раундами общения в парах и мини-группах, чтобы снять эмоциональные барьеры и помочь участникам узнать друг друга, а завершится час короткой рефлексией и формулированием целей на программу — участники ответят, зачем они здесь и что хотят получить по итогам трёх дней.', 0, '{}', '2026-04-23 07:03:33.824038+00', '2026-04-26 08:45:35.538213+00');
